var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그 기계야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきたあのマシンだからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this machine, that you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，它是必不可少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그 기계와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まであのマシンとともにいることを。`,ENG:`that you'll be with it, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和它一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called it to your office. It said it'd be here soon.`,TWN:`做好心理準備後，你將它傳喚到老闆辦公室，它說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`TANK_ADMIN_NULL_NULL`,text:{KOREA:`좋습니다.`,JPN:`委細承知しました。`,ENG:`Okay.`,TWN:`好的。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`TANK_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`TANK_ADMIN_NULL_NULL`,text:{KOREA:`제 성능을 감안했을 때, 이것은 아주 이상적인 제안이라고 생각합니다.`,JPN:`私の性能を鑑みるに、これは非常に理想的な提案だと思われます。`,ENG:`Considering my specs, I can only consider that this as an ideal offer.`,TWN:`考慮到我的性能，我認為這是非常理想的提案。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`TANK_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`TANK_ADMIN_NULL_NULL`,text:{KOREA:`이 순간을 축하하기 위해 서로의 손뼉을 칠 수 있다면 멋지겠지만, 지금의 몸으론 힘들겠네요.`,JPN:`この瞬間を祝うために手を叩き合えるならそうしたいところですが、今のボディでは無理そうです。`,ENG:`I would give you five to celebrate this moment if I were less bulky and had hands.`,TWN:`為了慶祝這一刻，如果我們能互相擊掌就太棒了，但以我現在的身體很難做到呢。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`TANK_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`TANK_ADMIN_NULL_NULL`,text:{KOREA:`하지만 괜찮습니다.`,JPN:`ですが、構いません。`,ENG:`But it's okay.`,TWN:`但沒關係。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`TANK_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`TANK_ADMIN_NULL_NULL`,text:{KOREA:`저흰 언제나 함께일 테니, 손뼉을 마주칠 기회도 결국 오게 될 것입니다.`,JPN:`これからは常に行動を共にするのですから、いずれ手を叩き合う機会も訪れるでしょう。`,ENG:`We'll always be together, and the time will come when we'll be able to slap our palms against each other's.`,TWN:`畢竟我們會一直在一起，總有一天，互相擊掌的機會會到來吧。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`TANK_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`TANK_ADMIN_NULL_NULL`,text:{KOREA:`그러니 지금은 관리국과 그 의지를 수호하는 일에 전념하고자 합니다.`,JPN:`ですので、今は管理局とその意志を守護する仕事に専念したいと思います。`,ENG:`So for now, I would like to devote myself to protecting the Administration and its will.`,TWN:`所以，我們現在還是專注在守護管理局，以及它的意志上面吧。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`TANK_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`TANK_ADMIN_NULL_NULL`,text:{KOREA:`우리 함께 열심히 해봅시다.`,JPN:`一緒に頑張りましょう。`,ENG:`I look forward to our future.`,TWN:`讓我們一起盡心盡力吧。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`TANK_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};